compliant:
public static Task<string> ReadFileAsync(string fileName)
{
  if (fileName == null) // Compliant: validation is done before async method
    throw new ArgumentNullException(nameof(fileName));

  return ReadFileAsyncCore(fileName);
}

private static async Task<string> ReadFileAsyncCore(string fileName)
{
  using var reader = File.OpenText(fileName);
  return await reader.ReadToEndAsync();
}
